package com.lin.ninisoul

object RecipeData {
    val recipes: List<Recipe> = listOf(
        Recipe("Ugali Nyama Choma", listOf("maize flour", "beef", "onions"), "2 cups maize flour; 500g beef, cut into pieces; salt to taste", "Light the grill or charcoal and grill the beef pieces until cooked through and slightly charred on the outside, turning occasionally, about 20 to 25 minutes. While the meat grills, bring water to a boil in a sufuria and gradually stir in the maize flour, mixing continuously until it thickens into a firm, smooth ugali. Serve the ugali hot alongside the grilled beef."),
        Recipe("Pilau na Kachumbari", listOf("rice", "beef", "pilau masala"), "2 cups rice; 400g beef, cubed; 2 tablespoons pilau masala; 1 onion, sliced; 2 cups water; 3 tomatoes, chopped; 1 onion, sliced (for salad)", "Brown the beef with the sliced onion in a sufuria until well seared. Stir in the pilau masala and cook for a minute until fragrant. Add the rice and water, stir once, then cover and simmer on low heat for 20 to 25 minutes until the rice is fully cooked and fragrant. While the pilau cooks, prepare the kachumbari by mixing the chopped tomatoes and sliced onion together. Serve the pilau hot with the fresh kachumbari on the side."),
        Recipe("Githeri Special", listOf("maize", "beans", "carrots"), "2 cups maize; 2 cups beans; 2 carrots, diced; 1 onion, sliced; 2 tablespoons cooking oil; salt to taste", "Boil the maize and beans together in plenty of water until both are fully soft, which can take 45 minutes to an hour, or use pre-boiled maize and beans to save time. In a separate pan, heat the oil and fry the onion and diced carrots until softened. Add the boiled maize and beans to the pan and stir-fry everything together for 8 to 10 minutes so the flavors combine well. Season with salt and serve hot."),
        Recipe("Mukimo na Nyama", listOf("potatoes", "beef"), "4 potatoes, peeled and chopped; 500g beef, cubed; 1 bunch greens, chopped; 2 onions, sliced; 2 tomatoes, chopped; 2 cups water; salt to taste", "Boil the potatoes and chopped greens together until soft, then mash them thoroughly together to make mukimo. In a separate sufuria, brown the beef with one sliced onion, then add the tomatoes and water, cover, and simmer for 40 to 45 minutes until the beef is tender. Serve the mukimo alongside the beef stew."),
        Recipe("Wali wa Nazi na Samaki", listOf("rice", "fish"), "2 cups rice; 1 cup coconut milk; 1 cup water; 2 whole fish, cleaned; 1 onion, sliced; 2 tomatoes, chopped; salt and lemon to taste", "Cook the rice with the coconut milk and water together until fully done and fragrant, about 20 minutes. While the rice cooks, season the fish with salt and lemon, then fry it in a separate pan with the sliced onion and chopped tomatoes until cooked through and golden on both sides, about 10 to 12 minutes per side. Serve the coconut rice hot alongside the fried fish."),
        Recipe("Chapati na Kuku", listOf("wheat flour", "chicken"), "2 cups wheat flour; warm water as needed; 1 whole chicken, cut into pieces; 2 onions, sliced; 2 tomatoes, chopped; 2 tablespoons cooking oil; salt to taste", "Make a soft dough with the wheat flour and warm water, divide into balls, roll out thin, and fry each on a hot pan with a little oil until golden and slightly puffed on both sides. For the chicken stew, fry the onions until soft, add the tomatoes and cook into a sauce, then add the chicken pieces and simmer covered for 30 to 35 minutes until fully cooked. Serve the chapatis warm with the chicken stew."),
        Recipe("Matumbo na Ugali", listOf("matumbo", "maize flour"), "500g matumbo, cleaned and chopped; 2 cups maize flour; 1 onion, sliced; 2 tomatoes, chopped; 2 tablespoons cooking oil; salt to taste", "Boil the matumbo in water until tender, which can take 45 minutes to an hour depending on thickness, then drain. Heat the oil in a pan and fry the onion until soft, add the tomatoes and cook into a sauce, then add the boiled matumbo and fry together for 10 minutes so it absorbs the flavors. Meanwhile, prepare the ugali by boiling water and stirring in the maize flour until firm. Serve hot together."),
        Recipe("Biryani ya Nyama", listOf("rice", "beef"), "2 cups rice; 500g beef, cubed; 2 onions, sliced; 3 tomatoes, chopped; 2 tablespoons biryani spice mix; 2 tablespoons cooking oil; 2 cups water; salt to taste", "Brown the beef with the onions in a sufuria until well seared, about 8 minutes. Stir in the biryani spice mix and chopped tomatoes, then cook into a rich sauce. Add the rice and water, stir once, cover, and simmer on low heat for 20 to 25 minutes until the rice is fully cooked and the flavors have soaked through. Let it rest for 5 minutes before serving."),
        Recipe("Mahindi na Nyama", listOf("maize", "beef"), "2 cups whole maize kernels; 500g beef, cubed; 1 onion, sliced; 2 tomatoes, chopped; 2 cups water; salt to taste", "Boil the maize kernels in plenty of water until soft, about 40 to 50 minutes, or use pre-boiled maize. In a separate sufuria, brown the beef with the onion, add the tomatoes and water, then simmer covered for 40 minutes until the beef is tender. Serve the boiled maize alongside the beef stew, or stir them together for a heartier one-pot meal."),
        Recipe("Samaki wa Kupaka", listOf("fish", "coconut milk"), "2 whole fish, cleaned; 1 cup coconut milk; 1 onion, sliced; 2 tomatoes, chopped; 1 tablespoon cooking oil; salt and lemon to taste", "Season the fish with salt and lemon juice. Heat the oil in a pan and fry the onion until soft, add the tomatoes and cook briefly, then pour in the coconut milk and bring to a gentle simmer. Carefully place the fish into the sauce, cover, and cook on low heat for 12 to 15 minutes per side until the fish is fully cooked and the sauce has thickened slightly. Serve hot."),
        Recipe("Mutura na Kachumbari", listOf("mutura", "tomatoes"), "2 pieces mutura (traditional sausage); 3 tomatoes, chopped; 1 onion, sliced; salt and pepper to taste", "Grill or boil the mutura over medium heat, turning occasionally, until heated through and lightly charred on the outside, about 15 to 20 minutes. While it cooks, prepare the kachumbari by mixing the chopped tomatoes, sliced onion, salt and pepper together in a bowl. Slice the mutura into pieces and serve alongside the fresh kachumbari."),
        Recipe("Irio na Nyama", listOf("potatoes", "beef"), "4 potatoes, peeled and chopped; 1 cup peas; 500g beef, cubed; 2 onions, sliced; 2 tomatoes, chopped; salt to taste", "Boil the potatoes and peas together until soft, then mash them together to make irio. In a separate sufuria, brown the beef with one sliced onion, add the tomatoes, and simmer covered for 40 to 45 minutes with a little water until the beef is tender. Serve the mashed irio alongside the beef stew."),
        Recipe("Kienyeji Chicken Stew", listOf("chicken", "tomatoes"), "1 free-range chicken, cut into pieces; 3 tomatoes, chopped; 2 onions, sliced; 2 tablespoons cooking oil; 1 cup water; salt to taste", "Heat the oil in a sufuria and fry the onions until soft, then add the tomatoes and cook down into a rich sauce. Add the chicken pieces and water, cover, and simmer slowly on low heat for 45 minutes to an hour, since free-range chicken takes longer to become tender than broiler chicken. Stir occasionally and season with salt before serving."),
        Recipe("Ugali Omena", listOf("omena", "maize flour"), "200g omena (silver fish), washed; 2 cups maize flour; 1 onion, sliced; 2 tomatoes, chopped; 2 tablespoons cooking oil; salt to taste", "Heat the oil in a pan and fry the onion until soft, add the tomatoes and cook into a sauce, then add the washed omena and simmer for 10 minutes, stirring occasionally, until well combined and heated through. Meanwhile, boil water in a sufuria and gradually stir in the maize flour until it thickens into firm ugali. Serve hot together."),
        Recipe("Managu na Ugali", listOf("managu", "maize flour"), "1 large bunch managu, washed and chopped; 2 cups maize flour; 1 onion, sliced; 2 tomatoes, chopped; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a sufuria and fry the onion until soft, add the tomatoes and cook briefly into a light sauce, then add the chopped managu and simmer for 10 to 12 minutes until tender, stirring occasionally. Meanwhile, prepare the ugali by boiling water and stirring in the maize flour until firm and smooth. Serve the managu alongside the ugali."),
        Recipe("Ndengu na Wali", listOf("ndengu", "rice"), "2 cups pre-boiled ndengu (green grams); 2 cups rice; 1 onion, sliced; 2 tomatoes, chopped; 2 tablespoons cooking oil; salt to taste", "Cook the rice according to package instructions until fluffy. In a separate pan, heat the oil and fry the onion until soft, add the tomatoes and cook into a sauce, then add the pre-boiled ndengu and simmer for 10 minutes so the flavors combine. Serve the ndengu stew hot over the cooked rice."),
        Recipe("Chapati na Maharagwe", listOf("wheat flour", "beans"), "2 cups wheat flour; warm water as needed; 2 cups pre-boiled beans; 1 onion, sliced; 2 tomatoes, chopped; 2 tablespoons cooking oil; salt to taste", "Make a soft dough with the flour and warm water, roll into thin rounds, and fry each on a hot pan with a little oil until golden on both sides. For the beans, fry the onion until soft, add the tomatoes and cook into a sauce, then add the pre-boiled beans and simmer for 10 minutes. Serve the warm chapatis with the beans stew."),
        Recipe("Mbaazi za Nazi", listOf("mbaazi", "coconut milk"), "2 cups pre-boiled mbaazi (pigeon peas); 1 cup coconut milk; 1 onion, sliced; 1 tomato, chopped; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a sufuria and fry the onion until soft, add the chopped tomato and cook briefly. Pour in the coconut milk and bring to a gentle simmer, then add the pre-boiled mbaazi and continue simmering for 10 minutes until everything is well combined and heated through. Season with salt and serve."),
        Recipe("Sukuma Wiki na Nyama", listOf("sukuma wiki", "beef"), "1 large bunch sukuma wiki (kale), chopped; 500g beef, cubed; 1 onion, sliced; 2 tomatoes, chopped; 2 tablespoons cooking oil; 1 cup water; salt to taste", "Brown the beef with the sliced onion in a sufuria, add the tomatoes and water, then cover and simmer for 40 to 45 minutes until the beef is tender. In a separate pan, sauté the chopped sukuma wiki in a little oil for 6 to 8 minutes until tender. Serve the sukuma wiki alongside the beef stew."),
        Recipe("Tilapia na Ugali", listOf("fish", "maize flour"), "1 whole tilapia, cleaned; 2 cups maize flour; 1 onion, sliced; salt and lemon to taste; 2 tablespoons cooking oil", "Season the fish with salt and lemon, then fry it in hot oil with the sliced onion until golden and cooked through, about 10 to 12 minutes per side. Meanwhile, boil water in a sufuria and gradually stir in the maize flour, mixing continuously until it thickens into firm ugali. Serve the fried fish hot alongside the ugali."),
        Recipe("Nyama Stew", listOf("beef", "carrots", "potatoes"), "500g beef, cubed; 2 carrots, sliced; 3 potatoes, cubed; 1 onion, sliced; 2 tomatoes, chopped; 2 cups water; salt to taste", "Brown the beef with the onion in a sufuria over medium-high heat. Add the tomatoes and cook into a sauce, then add the carrots, potatoes, and water. Cover and simmer for 40 to 45 minutes, stirring occasionally, until the beef is tender and the vegetables are fully cooked. Season with salt and serve hot."),
        Recipe("Chips Masala", listOf("potatoes", "tomato sauce"), "4 potatoes, cut into chips; oil for deep frying; half cup tomato sauce; 1 onion, sliced; 1 teaspoon chili powder; salt to taste", "Deep fry the potato chips in hot oil until golden and crispy, then drain on paper towels. In a separate pan, fry the onion briefly, then stir in the tomato sauce and chili powder to make a spicy masala sauce. Toss the fried chips in the sauce until well coated and serve immediately while hot."),
        Recipe("Fish Fingers", listOf("fish", "breadcrumbs"), "500g fish fillets, cut into strips; 1 cup breadcrumbs; 2 eggs, beaten; half cup flour; oil for frying; salt to taste", "Season the fish strips with salt. Dip each strip first in flour, then in beaten egg, then coat thoroughly in breadcrumbs. Heat oil in a pan and fry the coated fish strips until golden brown and crispy on all sides, about 3 to 4 minutes per side. Serve hot with your preferred dipping sauce."),
        Recipe("Beef Samosa", listOf("wheat flour", "beef"), "2 cups wheat flour; warm water as needed; 300g minced beef; 1 onion, chopped; 1 teaspoon curry powder; oil for frying; salt to taste", "Make a stiff dough with the flour and water, then roll out thin and cut into samosa wrapper shapes. For the filling, fry the minced beef with the onion and curry powder until fully cooked and dry. Fill each wrapper with the beef mixture, fold into a triangle shape, seal the edges, and deep fry until golden and crispy."),
        Recipe("Mandazi", listOf("wheat flour", "sugar"), "2 cups wheat flour; half cup sugar; 1 teaspoon cardamom powder; 1 cup coconut milk; oil for frying", "Mix the flour, sugar, and cardamom powder together, then gradually add the coconut milk to form a soft dough. Knead well, then let it rest for 20 minutes. Roll out and cut into triangles or squares, then deep fry in hot oil until golden brown and puffed up on both sides. Drain and serve warm."),
        Recipe("Pumpkin Soup", listOf("pumpkin", "onions"), "1 medium pumpkin, peeled and chopped; 1 onion, sliced; 2 cups water or stock; salt and pepper to taste", "Boil the chopped pumpkin and sliced onion together in the water until the pumpkin is completely soft, about 20 minutes. Blend the mixture until smooth using a blender or masher. Return to the pot, season with salt and pepper, and simmer for a few more minutes before serving hot."),
        Recipe("Roasted Maize", listOf("maize"), "2 pieces fresh maize on the cob; pinch of salt", "Light a charcoal fire or grill and place the maize directly over the heat. Turn frequently every few minutes to ensure even roasting on all sides, until the kernels are slightly charred and tender, about 15 to 20 minutes total. Sprinkle with a little salt before serving hot."),
        Recipe("Boiled Nduma", listOf("nduma"), "2 pieces nduma (arrowroot), peeled; water for boiling; pinch of salt", "Place the peeled nduma into a sufuria with enough water to cover them and a pinch of salt. Bring to a boil, then reduce heat and simmer for 20 to 25 minutes until completely soft when pierced with a fork. Drain and serve warm, either on their own or alongside tea."),
        Recipe("Sweet Potatoes", listOf("sweet potatoes"), "4 sweet potatoes, peeled; water for steaming", "Place the peeled sweet potatoes in a steamer or a sufuria with a small amount of water and cover tightly. Steam for 20 to 25 minutes until completely soft when pierced with a fork. Serve warm on their own as a snack or alongside tea."),
        Recipe("Kachumbari", listOf("tomatoes", "onions"), "3 tomatoes, finely chopped; 1 onion, finely chopped; 1 green chili, chopped (optional); juice of half a lemon; salt to taste", "Combine the chopped tomatoes and onions in a bowl. Add the chopped chili if using, then squeeze in the lemon juice and season with salt. Mix everything together gently and let it sit for 10 minutes before serving so the flavors blend together nicely."),
        Recipe("Cabbage Stew", listOf("cabbage", "carrots"), "Half a cabbage, shredded; 2 carrots, grated; 1 onion, sliced; 2 tablespoons cooking oil; salt to taste", "Heat the oil in a frying pan and fry the onion until soft. Add the grated carrots and cook for 2 minutes, then add the shredded cabbage and stir well. Cover and cook for 6 to 8 minutes, stirring occasionally, until the cabbage is tender but still has a slight bite. Season with salt and serve."),
        Recipe("Peas Stew", listOf("peas", "potatoes"), "2 cups green peas; 2 potatoes, cubed; 1 onion, sliced; 1 tomato, chopped; 1 tablespoon cooking oil; 1 cup water; salt to taste", "Heat the oil and fry the onion until soft, add the chopped tomato and cook briefly into a sauce. Add the cubed potatoes and water, cover, and simmer for 12 to 15 minutes until the potatoes begin to soften. Stir in the peas and cook for another 5 minutes until everything is tender. Season and serve."),
        Recipe("Egg Curry", listOf("eggs", "tomatoes"), "4 eggs; 2 tomatoes, chopped; 1 onion, sliced; 1 teaspoon curry powder; 1 tablespoon cooking oil; salt to taste", "Boil the eggs for 8 to 10 minutes until fully hardboiled, then peel and set aside. In a separate pan, fry the onion until soft, add the tomatoes and curry powder, and simmer into a thick sauce. Add the boiled eggs to the sauce, gently coating them, and simmer for 5 more minutes before serving."),
        Recipe("Liver Stew", listOf("liver", "onions"), "300g liver, sliced; 1 onion, sliced; 1 tomato, chopped; 1 tablespoon cooking oil; salt and pepper to taste", "Heat the oil in a pan over medium-high heat and fry the onion until soft. Add the sliced liver and fry briefly for 4 to 5 minutes, since liver becomes tough if overcooked. Add the chopped tomato and simmer for 3 to 4 more minutes. Season with salt and pepper and serve immediately."),
        Recipe("Chicken Fry", listOf("chicken", "onions"), "500g chicken pieces; 1 onion, sliced; 1 tablespoon cooking oil; salt and pepper to taste", "Season the chicken pieces with salt and pepper. Heat the oil in a frying pan over medium heat and fry the onion until soft. Add the chicken pieces and fry, turning occasionally, for 20 to 25 minutes until golden brown on the outside and fully cooked through inside. Serve hot."),
        Recipe("Coconut Beans", listOf("beans", "coconut milk"), "2 cups pre-boiled beans; 1 cup coconut milk; 1 onion, sliced; 1 tomato, chopped; 1 tablespoon cooking oil; salt to taste", "Heat the oil and fry the onion until soft, add the chopped tomato and cook briefly. Pour in the coconut milk and bring to a gentle simmer, then add the pre-boiled beans and continue simmering for 10 to 12 minutes until well combined and the sauce has slightly thickened. Season and serve."),
        Recipe("Rice and Peas", listOf("rice", "peas"), "2 cups rice; 1 cup green peas; 1 onion, sliced; 1 tablespoon cooking oil; water as needed; salt to taste", "Heat the oil in a sufuria and fry the onion briefly until fragrant. Add the rice and enough water according to package instructions, stir in the peas, then cover and cook on low heat until the rice is fully cooked and fluffy, about 15 to 18 minutes. Season with salt and serve."),
        Recipe("Spiced Tea", listOf("tea leaves", "milk"), "2 cups milk; 1 cup water; 1 teaspoon black tea leaves; 2 cardamom pods; sugar to taste", "Bring the water and milk to a boil together in a small saucepan. Add the tea leaves and cardamom pods, then reduce heat and simmer for 5 minutes, allowing the flavors to infuse. Strain into cups, add sugar to taste, and serve hot."),
        Recipe("Porridge", listOf("flour", "water"), "1 cup millet or wheat flour; 3 cups water; sugar or salt to taste", "Mix the flour with a little cold water first to form a smooth paste with no lumps. Bring the remaining water to a boil in a sufuria, then gradually stir in the flour paste, whisking continuously to avoid lumps. Simmer for 8 to 10 minutes, stirring occasionally, until thickened. Sweeten or salt to taste and serve warm."),
        Recipe("Avocado Salad", listOf("avocado", "tomatoes"), "1 ripe avocado, sliced; 2 tomatoes, sliced; salt and pepper to taste; squeeze of lemon", "Arrange the sliced avocado and tomatoes together on a plate. Season with salt, pepper, and a squeeze of fresh lemon juice. Toss gently to combine, being careful not to mash the avocado, and serve immediately while fresh."),
        Recipe("Beef Burger", listOf("mince", "bread"), "300g minced beef; 2 burger buns; 1 onion, finely chopped; salt and pepper to taste; lettuce and tomato for serving", "Mix the minced beef with the chopped onion, salt, and pepper, then shape into patties. Grill or fry the patties over medium-high heat for 4 to 5 minutes per side until fully cooked through. Toast the buns lightly, then assemble the burger with lettuce, tomato, and the cooked patty. Serve immediately."),
        Recipe("Potato Bhajia", listOf("potatoes", "flour"), "4 potatoes, thinly sliced; 1 cup flour; half teaspoon turmeric; half teaspoon chili powder; water as needed; oil for frying; salt to taste", "Mix the flour with turmeric, chili powder, and salt, then gradually add water to make a smooth batter. Dip each potato slice into the batter, coating well, then deep fry in hot oil until golden and crispy on both sides, about 3 to 4 minutes per side. Drain and serve hot."),
        Recipe("Vegetable Rice", listOf("rice", "mixed veggies"), "2 cups rice; 1 cup mixed vegetables (carrots, peas, beans); 1 onion, sliced; 1 tablespoon cooking oil; water as needed; salt to taste", "Heat the oil in a sufuria and fry the onion until soft. Add the mixed vegetables and stir-fry briefly for 3 minutes. Add the rice and enough water according to package instructions, cover, and simmer on low heat for 15 to 18 minutes until the rice is fully cooked and fluffy. Season and serve."),
        Recipe("Sausage Stew", listOf("sausages", "onions"), "4 sausages, sliced; 1 onion, sliced; 1 tomato, chopped; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a pan and fry the sliced sausages until browned on all sides, about 5 minutes. Add the onion and cook until soft, then add the chopped tomato and simmer together for 8 to 10 minutes until the sauce thickens slightly. Season with salt and serve hot."),
        Recipe("Fried Liver", listOf("liver", "garlic"), "300g liver, sliced; 2 cloves garlic, minced; 1 tablespoon cooking oil; salt and pepper to taste", "Heat the oil in a pan over high heat until very hot. Add the minced garlic and fry briefly until fragrant, about 30 seconds. Add the sliced liver and fry quickly for 3 to 4 minutes per side, taking care not to overcook since liver toughens quickly. Season with salt and pepper and serve immediately."),
        Recipe("Mixed Fruit Salad", listOf("fruits"), "Assorted fruits such as mango, banana, watermelon, and pineapple, chopped; squeeze of lemon", "Wash and chop all the fruits into bite-sized pieces. Combine them together in a large bowl. Add a small squeeze of lemon juice to keep the fruit fresh and add a touch of brightness. Toss gently and serve chilled."),
        Recipe("Boiled Green Maize", listOf("maize"), "2 pieces fresh green maize on the cob; water for boiling; pinch of salt", "Place the maize cobs into a large sufuria with enough water to fully cover them. Add a pinch of salt, bring to a boil, then reduce heat and simmer for 20 to 25 minutes until the kernels are tender. Drain and serve warm."),
        Recipe("Masala Tea", listOf("tea leaves", "ginger"), "2 cups milk; 1 cup water; 1 teaspoon black tea leaves; small piece of ginger, crushed; sugar to taste", "Bring the water and milk to a boil together with the crushed ginger. Add the tea leaves, reduce heat, and simmer for 5 minutes to allow the ginger and tea flavors to fully infuse. Strain into cups, add sugar to taste, and serve hot."),
        Recipe("Plain Ugali", listOf("maize flour"), "2 cups maize flour; 4 cups water; pinch of salt", "Bring the water to a rolling boil in a sufuria with a pinch of salt. Gradually add the maize flour while stirring continuously and vigorously with a wooden spoon to avoid lumps forming. Keep stirring and pressing for 8 to 10 minutes until the mixture thickens into a firm, smooth dough-like consistency. Serve hot."),
        Recipe("Bean Stew", listOf("beans", "tomatoes"), "2 cups pre-boiled beans; 2 tomatoes, chopped; 1 onion, sliced; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a sufuria and fry the onion until soft. Add the chopped tomatoes and cook down into a thick sauce, about 6 minutes. Add the pre-boiled beans along with a little of their cooking liquid, then simmer for 10 to 12 minutes so the flavors combine well. Season with salt and serve hot."),
        Recipe("Spaghetti Bolognese", listOf("spaghetti", "mince", "tomatoes"), "200g spaghetti; 300g minced beef; 2 tomatoes, chopped; 1 onion, chopped; 2 cloves garlic, minced; salt to taste", "Boil the spaghetti in salted water until al dente, then drain and set aside. In a separate pan, brown the minced beef with the onion and garlic until fully cooked. Add the chopped tomatoes and simmer for 10 to 12 minutes into a rich sauce. Toss the cooked spaghetti through the sauce and serve hot."),
        Recipe("Vegetable Stir Fry", listOf("broccoli", "carrots", "soy sauce"), "1 head broccoli, cut into florets; 2 carrots, sliced; 2 cloves garlic, minced; 2 tablespoons soy sauce; 1 tablespoon cooking oil", "Heat the oil in a wok or large pan over high heat. Add the garlic and fry briefly until fragrant. Add the carrots and stir-fry for 2 minutes, then add the broccoli and continue stir-frying for another 3 to 4 minutes until just tender but still crisp. Add the soy sauce, toss well, and serve immediately."),
        Recipe("Chicken Curry", listOf("chicken", "onions", "curry"), "500g chicken pieces; 2 onions, sliced; 2 tablespoons curry powder; 2 tomatoes, chopped; 1 cup water; salt to taste", "Heat oil in a sufuria and fry the onions until golden, about 5 minutes. Stir in the curry powder and cook for a minute until fragrant. Add the tomatoes and cook into a sauce, then add the chicken pieces and water. Cover and simmer for 30 to 35 minutes until the chicken is fully cooked and tender. Season and serve."),
        Recipe("Classic Pancakes", listOf("flour", "eggs", "milk"), "1 cup flour; 2 eggs; 1 cup milk; 1 tablespoon sugar; pinch of salt; butter for frying", "Whisk the flour, eggs, milk, sugar, and salt together until you have a smooth, lump-free batter. Heat a lightly buttered pan over medium heat and pour in a small amount of batter, swirling to coat the pan thinly. Cook for 1 to 2 minutes until golden, then flip and cook the other side. Repeat with remaining batter."),
        Recipe("Greek Salad", listOf("cucumber", "tomatoes", "feta"), "1 cucumber, chopped; 2 tomatoes, chopped; half cup feta cheese, cubed; handful olives; 1 tablespoon olive oil; salt and pepper to taste", "Combine the chopped cucumber and tomatoes in a large bowl. Add the cubed feta cheese and olives on top. Drizzle with olive oil and season with salt and pepper. Toss gently just before serving so the feta doesn't break apart too much."),
        Recipe("Omelette", listOf("eggs", "onions", "tomatoes"), "3 eggs; 1 onion, finely chopped; 1 tomato, chopped; 1 tablespoon cooking oil; salt and pepper to taste", "Whisk the eggs together with salt and pepper until well combined. Heat the oil in a pan and fry the onion and tomato briefly until just softened. Pour the whisked eggs over the vegetables and cook on medium-low heat, lifting the edges gently, until just set, about 3 to 4 minutes. Fold and serve."),
        Recipe("Lentil Soup", listOf("lentils", "carrots"), "1 cup lentils; 1 carrot, diced; 1 onion, chopped; 3 cups water or stock; salt and pepper to taste", "Combine the lentils, diced carrot, and chopped onion together in a pot with the water or stock. Bring to a boil, then reduce heat and simmer for 25 to 30 minutes until the lentils are completely soft and the soup has thickened slightly. Season with salt and pepper, and blend lightly if a smoother texture is preferred."),
        Recipe("Mashed Potatoes", listOf("potatoes", "milk", "butter"), "4 potatoes, peeled and chopped; half cup milk; 2 tablespoons butter; salt to taste", "Boil the chopped potatoes in salted water until completely soft, about 18 to 20 minutes, then drain well. Mash the potatoes thoroughly using a fork or masher. Add the milk and butter, then continue mashing and stirring until smooth and creamy. Season with salt to taste and serve hot."),
        Recipe("Tuna Sandwich", listOf("tuna", "bread", "mayonnaise"), "1 can tuna, drained; 2 slices bread; 2 tablespoons mayonnaise; salt and pepper to taste", "Drain the tuna well and place it in a bowl. Add the mayonnaise and mix thoroughly until well combined, then season with salt and pepper. Spread the tuna mixture evenly onto one slice of bread, top with the second slice, and serve, cutting in half if desired."),
        Recipe("Fried Rice", listOf("rice", "eggs", "peas"), "2 cups pre-cooked rice; 2 eggs; half cup peas; 1 onion, chopped; 2 tablespoons cooking oil; soy sauce to taste", "Heat the oil in a large pan or wok and fry the onion until soft. Push to one side, crack in the eggs, and scramble until just set. Add the pre-cooked rice and peas, breaking up any clumps, and stir-fry everything together for 5 to 6 minutes. Add soy sauce to taste and serve hot."),
        Recipe("Margherita Pizza", listOf("flour", "tomatoes", "mozzarella"), "2 cups flour; 1 cup tomato sauce; 200g mozzarella, sliced; 1 teaspoon yeast; warm water as needed; salt to taste", "Mix the flour, yeast, salt, and warm water together to form a soft dough, then let it rest for 30 minutes until slightly risen. Roll out thinly on a floured surface, spread the tomato sauce evenly across the top, and arrange the mozzarella slices on top. Bake in a hot oven at 220°C for 12 to 15 minutes until the crust is golden and the cheese is bubbling."),
        Recipe("Grilled Cheese", listOf("bread", "cheddar"), "2 slices bread; 50g cheddar cheese, sliced; 1 tablespoon butter", "Butter one side of each bread slice. Place the cheese between the two slices, buttered sides facing outward. Heat a pan over medium heat and place the sandwich in, pressing down gently. Cook for 2 to 3 minutes per side until golden brown and the cheese has fully melted inside."),
        Recipe("Mac and Cheese", listOf("macaroni", "cheddar"), "200g macaroni pasta; 100g cheddar cheese, grated; 1 cup milk; 1 tablespoon flour; 1 tablespoon butter; salt to taste", "Boil the macaroni according to package instructions until al dente, then drain. In a separate pan, melt the butter, whisk in the flour, then gradually add the milk while whisking to form a smooth sauce. Stir in the grated cheese until melted. Combine the sauce with the cooked macaroni and serve hot."),
        Recipe("Mushroom Pasta", listOf("pasta", "mushrooms"), "200g pasta; 150g mushrooms, sliced; 2 cloves garlic, minced; 2 tablespoons cooking oil; salt and pepper to taste", "Boil the pasta in salted water until al dente, then drain, reserving a little of the pasta water. In a separate pan, heat the oil and fry the garlic briefly until fragrant, then add the sliced mushrooms and cook until softened, about 6 to 8 minutes. Toss the cooked pasta through the mushrooms, adding a splash of the reserved pasta water if needed, and season with salt and pepper before serving."),
        Recipe("Caesar Salad", listOf("lettuce", "chicken"), "1 head lettuce, chopped; 1 chicken breast, cooked and sliced; 2 tablespoons Caesar dressing; grated parmesan to taste", "Cook the chicken breast by grilling or pan-frying until fully cooked through, then slice it into strips. Arrange the chopped lettuce in a bowl, top with the sliced chicken, and drizzle with Caesar dressing. Sprinkle grated parmesan on top, toss gently, and serve immediately."),
        Recipe("Beef Tacos", listOf("beef", "tortillas"), "300g minced beef; 4 taco shells or tortillas; 1 onion, chopped; 1 teaspoon taco seasoning; lettuce and tomato for topping", "Fry the minced beef with the chopped onion in a pan until fully browned and cooked through. Stir in the taco seasoning and a splash of water, then simmer for 5 minutes until well combined. Warm the taco shells briefly, then fill each with the beef mixture, lettuce, and tomato. Serve immediately."),
        Recipe("Spanish Omelette", listOf("eggs", "potatoes"), "4 eggs; 2 potatoes, thinly sliced; 1 onion, sliced; 2 tablespoons cooking oil; salt to taste", "Heat the oil in a pan and fry the sliced potatoes and onion together until soft, about 12 to 15 minutes, turning occasionally. Whisk the eggs with salt, then pour over the potato and onion mixture in the pan. Cook on low heat until the bottom sets, then carefully flip and cook the other side until fully set, about 5 minutes per side."),
        Recipe("Vegetable Curry", listOf("cauliflower", "peas"), "Half a head cauliflower, cut into florets; half cup peas; 1 onion, chopped; 1 tablespoon curry powder; 1 cup water; salt to taste", "Heat oil in a pan and fry the onion until soft, then stir in the curry powder and cook for a minute until fragrant. Add the cauliflower florets and water, cover, and simmer for 12 to 15 minutes until the cauliflower softens. Stir in the peas and cook for 5 more minutes. Season with salt and serve."),
        Recipe("Baked Potato", listOf("potatoes", "cheese"), "2 large potatoes; 50g cheese, grated; 1 tablespoon butter; salt to taste", "Wash the potatoes thoroughly and pierce each one several times with a fork. Bake in a preheated oven at 200°C for 45 to 50 minutes until the skin is crisp and the inside is fully soft. Slice each potato open, fluff the inside with a fork, then top with butter and grated cheese before serving."),
        Recipe("Chicken Parmesan", listOf("chicken", "mozzarella"), "1 chicken breast, sliced thin; 50g mozzarella, sliced; half cup breadcrumbs; 1 egg, beaten; half cup tomato sauce; salt to taste", "Dip the chicken slices in beaten egg, then coat thoroughly in breadcrumbs. Fry in a pan until golden on both sides, about 4 minutes per side. Place the fried chicken in a baking dish, top with tomato sauce and mozzarella slices, then bake at 200°C for 10 to 12 minutes until the cheese melts and bubbles."),
        Recipe("Pasta Carbonara", listOf("pasta", "eggs", "cheese"), "200g pasta; 2 eggs; half cup grated cheese; 100g bacon or beef bits; salt and pepper to taste", "Boil the pasta in salted water until al dente, then drain, reserving a little pasta water. Fry the bacon or beef bits until crispy. Whisk the eggs and cheese together in a bowl. Off the heat, quickly toss the hot pasta with the egg mixture and bacon, adding a splash of pasta water, stirring fast so the eggs turn creamy and don't scramble."),
        Recipe("Beef Stroganoff", listOf("beef", "cream"), "300g beef, sliced thin; half cup cream; 1 onion, sliced; 150g mushrooms, sliced; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a pan and fry the beef strips quickly until browned, then set aside. In the same pan, fry the onion and mushrooms until soft. Return the beef to the pan, pour in the cream, and simmer gently for 8 to 10 minutes until the sauce thickens slightly. Season with salt and serve hot, ideally over rice or pasta."),
        Recipe("Fish Tacos", listOf("fish", "tortillas"), "2 fish fillets; 4 taco shells or tortillas; half cup flour; oil for frying; lettuce and lime for topping", "Coat the fish fillets lightly in flour and fry in hot oil until golden and cooked through, about 4 minutes per side. Break the cooked fish into smaller pieces. Warm the taco shells, then fill each with the fish, shredded lettuce, and a squeeze of lime. Serve immediately while warm."),
        Recipe("Tomato Soup", listOf("tomatoes", "cream"), "6 tomatoes, chopped; 1 onion, chopped; quarter cup cream; 2 cups water or stock; salt and pepper to taste", "Boil the chopped tomatoes and onion together in the water or stock until fully soft, about 20 minutes. Blend the mixture until smooth using a blender. Return to the pot, stir in the cream, and gently warm through without boiling. Season with salt and pepper before serving."),
        Recipe("Garlic Bread", listOf("bread", "garlic"), "4 slices bread; 2 cloves garlic, minced; 2 tablespoons butter, softened; pinch of salt", "Mix the softened butter with the minced garlic and a pinch of salt until well combined. Spread the garlic butter generously over each slice of bread. Toast under a grill or in a hot oven at 200°C for 5 to 7 minutes until golden and crisp at the edges. Serve warm."),
        Recipe("Baked Salmon", listOf("salmon", "lemon"), "1 salmon fillet; 1 lemon, sliced; 1 tablespoon olive oil; salt and pepper to taste", "Place the salmon fillet on a baking tray lined with foil. Drizzle with olive oil, season with salt and pepper, and lay the lemon slices on top. Bake in a preheated oven at 200°C for 15 to 18 minutes until the salmon is cooked through and flakes easily with a fork. Serve immediately."),
        Recipe("Rice Pudding", listOf("rice", "milk"), "1 cup rice; 2 cups milk; quarter cup sugar; pinch of cinnamon", "Combine the rice and milk in a pot and bring to a gentle simmer. Cook on low heat, stirring occasionally, for 25 to 30 minutes until the rice is very soft and the mixture has thickened into a creamy pudding. Stir in the sugar and a pinch of cinnamon, then serve warm or chilled."),
        Recipe("Banana Bread", listOf("flour", "bananas"), "2 cups flour; 3 ripe bananas, mashed; half cup sugar; 2 eggs; 1 teaspoon baking powder; quarter cup oil", "Mash the bananas thoroughly in a bowl, then mix in the sugar, eggs, and oil until well combined. Fold in the flour and baking powder gently until just combined, avoiding overmixing. Pour the batter into a greased loaf pan and bake at 180°C for 50 to 55 minutes until a skewer inserted comes out clean."),
        Recipe("Scrambled Eggs", listOf("eggs", "milk"), "3 eggs; 1 tablespoon milk; 1 teaspoon butter; salt and pepper to taste", "Whisk the eggs together with the milk, salt, and pepper until well combined. Melt the butter in a pan over low to medium heat. Pour in the egg mixture and stir gently and continuously with a spatula, cooking until softly set but not dry, about 3 to 4 minutes. Serve immediately."),
        Recipe("Potato Salad", listOf("potatoes", "mayonnaise"), "3 potatoes, boiled and cubed; 2 tablespoons mayonnaise; 1 small onion, finely chopped; salt and pepper to taste", "Boil the potatoes until just soft, then drain and let cool before cubing them. Combine the cubed potatoes with the chopped onion in a bowl. Add the mayonnaise and mix gently until everything is evenly coated. Season with salt and pepper, then chill briefly before serving."),
        Recipe("Bean Chili", listOf("beans", "tomatoes"), "2 cups pre-boiled beans; 2 tomatoes, chopped; 1 onion, chopped; 1 teaspoon chili powder; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a pot and fry the onion until soft. Add the chopped tomatoes and chili powder, then simmer until the tomatoes break down into a sauce, about 8 minutes. Add the pre-boiled beans and simmer for another 10 minutes so the flavors combine fully. Season with salt and serve hot."),
        Recipe("Chicken Skewers", listOf("chicken", "peppers"), "300g chicken, cubed; 2 peppers, cut into chunks; 1 tablespoon cooking oil; salt and pepper to taste", "Thread the cubed chicken and pepper chunks alternately onto skewers. Brush lightly with oil and season with salt and pepper. Grill over medium-high heat, turning occasionally, for 12 to 15 minutes until the chicken is fully cooked through and lightly charred on the outside. Serve hot."),
        Recipe("Fried Fish", listOf("fish", "flour"), "2 fish fillets; half cup flour; oil for frying; salt and lemon to taste", "Season the fish fillets with salt and a squeeze of lemon. Coat each fillet lightly and evenly in flour, shaking off any excess. Heat oil in a frying pan and fry the fish for 4 to 5 minutes per side until golden brown and fully cooked through. Drain briefly and serve hot."),
        Recipe("Coleslaw", listOf("cabbage", "mayonnaise"), "Half a cabbage, finely shredded; 1 carrot, grated; 2 tablespoons mayonnaise; salt and pepper to taste", "Combine the finely shredded cabbage and grated carrot together in a large bowl. Add the mayonnaise and mix thoroughly until everything is evenly coated. Season with salt and pepper to taste, then let it chill in the fridge for at least 15 minutes before serving for the best flavor."),
        Recipe("Apple Crumble", listOf("apples", "flour"), "3 apples, peeled and sliced; 1 cup flour; half cup sugar; quarter cup butter; pinch of cinnamon", "Arrange the sliced apples in a baking dish, sprinkling with a little sugar and cinnamon. Mix the flour, remaining sugar, and butter together with your fingers until it forms a crumbly texture. Sprinkle this crumble topping evenly over the apples. Bake at 180°C for 35 to 40 minutes until golden and bubbling."),
        Recipe("Smoothie", listOf("fruits", "yoghurt"), "1 banana; 1 cup yoghurt; handful of any other fruit; a little honey if desired", "Peel and chop the banana into chunks. Combine the banana, yoghurt, and any additional fruit together in a blender. Blend until completely smooth, adding a little honey if extra sweetness is desired. Pour into a glass and serve immediately while chilled."),
        Recipe("French Toast", listOf("bread", "eggs"), "2 slices bread; 1 egg; 2 tablespoons milk; 1 teaspoon sugar; butter for frying", "Whisk the egg, milk, and sugar together in a shallow bowl. Dip each slice of bread into the mixture, coating both sides well and letting it soak briefly. Melt butter in a pan over medium heat and fry each slice for 2 to 3 minutes per side until golden brown. Serve warm."),
        Recipe("Beef Stew", listOf("beef", "potatoes"), "500g beef, cubed; 3 potatoes, cubed; 1 onion, sliced; 2 tomatoes, chopped; 2 cups water; salt to taste", "Brown the beef in a sufuria over medium-high heat. Add the onion and cook until softened, then add the tomatoes and cook into a sauce. Add the potatoes and water, cover, and simmer for 40 to 45 minutes, stirring occasionally, until the beef is tender and the potatoes are fully cooked. Season and serve hot."),
        Recipe("Egg Fried Rice", listOf("rice", "eggs"), "2 cups pre-cooked rice; 2 eggs; 1 onion, chopped; 2 tablespoons cooking oil; soy sauce to taste", "Heat the oil in a pan and fry the onion until soft. Push to one side, crack in the eggs, and scramble until just set. Add the pre-cooked rice, breaking up any clumps with a spatula, and stir-fry everything together for 5 to 6 minutes. Add soy sauce to taste and serve hot."),
        Recipe("Baked Beans", listOf("beans", "tomato sauce"), "2 cups pre-boiled beans; half cup tomato sauce; 1 onion, chopped; 1 tablespoon cooking oil; salt to taste", "Heat the oil in a pan and fry the chopped onion until soft. Add the tomato sauce and a splash of water, stirring well, then add the pre-boiled beans. Simmer everything together gently for 10 minutes, stirring occasionally, until heated through and the sauce has thickened slightly. Season and serve."),
        Recipe("Grilled Chicken", listOf("chicken", "herbs"), "1 whole chicken or pieces; 1 tablespoon mixed herbs; 1 tablespoon cooking oil; salt and pepper to taste", "Rub the chicken all over with oil, mixed herbs, salt, and pepper, making sure to coat it evenly. Let it marinate for at least 20 minutes if time allows. Grill over medium heat, turning occasionally, for 30 to 40 minutes until the chicken is fully cooked through and golden on the outside. Serve hot."),
        Recipe("Pasta Primavera", listOf("pasta", "mixed veggies"), "200g pasta; 1 cup mixed vegetables (carrots, peas, peppers); 2 cloves garlic, minced; 2 tablespoons cooking oil; salt to taste", "Boil the pasta in salted water until al dente, then drain. In a separate pan, heat the oil and fry the garlic briefly until fragrant, then add the mixed vegetables and stir-fry for 5 to 6 minutes until just tender. Toss the cooked pasta through the vegetables, season with salt, and serve hot."),
        Recipe("Beef Kebabs", listOf("beef", "onions"), "300g beef, cubed; 1 onion, cut into chunks; 1 tablespoon cooking oil; salt and pepper to taste", "Thread the cubed beef and onion chunks alternately onto skewers. Brush lightly with oil and season with salt and pepper. Grill over medium-high heat, turning occasionally, for 10 to 12 minutes until the beef is cooked to your liking and nicely charred on the outside. Serve hot."),
        Recipe("Egg Salad", listOf("eggs", "mayonnaise"), "3 eggs; 1 tablespoon mayonnaise; salt and pepper to taste", "Boil the eggs for 8 to 10 minutes until fully hardboiled, then cool, peel, and chop them. Place the chopped eggs in a bowl and add the mayonnaise, mashing and mixing together until well combined. Season with salt and pepper to taste, then serve on its own, in a sandwich, or over salad leaves."),
        Recipe("Hummus", listOf("chickpeas", "garlic"), "1 cup pre-boiled chickpeas; 1 clove garlic; 2 tablespoons olive oil; juice of half a lemon; salt to taste", "Combine the chickpeas, garlic, olive oil, and lemon juice together in a blender or food processor. Blend until completely smooth, adding a splash of water if the mixture is too thick. Season with salt to taste and transfer to a bowl, drizzling with a little extra olive oil before serving."),
        Recipe("Curry Rice", listOf("rice", "curry powder"), "2 cups rice; 1 teaspoon curry powder; 1 onion, chopped; 1 tablespoon cooking oil; water as needed; salt to taste", "Heat the oil in a sufuria and fry the chopped onion until soft. Stir in the curry powder and cook briefly until fragrant. Add the rice and enough water according to package instructions, cover, and simmer on low heat for 15 to 18 minutes until the rice is fully cooked and fragrant. Season and serve."),
        Recipe("Steamed Broccoli", listOf("broccoli"), "1 head broccoli, cut into florets; pinch of salt", "Bring a small amount of water to a boil in a pot fitted with a steamer basket or sieve. Place the broccoli florets in the steamer above the boiling water, cover, and steam for 5 to 6 minutes until just tender but still bright green. Sprinkle with a little salt and serve immediately."),
        Recipe("Fruit Salad", listOf("fruits"), "Assorted fruits of your choice, chopped; squeeze of lemon", "Wash and chop all the chosen fruits into bite-sized pieces, removing any seeds or skins as needed. Combine everything together in a large bowl. Add a small squeeze of lemon juice to keep the fruit looking fresh and add a touch of brightness. Toss gently and serve chilled."),
        Recipe("Hot Chocolate", listOf("milk", "cocoa"), "1 cup milk; 1 teaspoon cocoa powder; sugar to taste", "Pour the milk into a small saucepan and heat gently over medium-low heat, stirring occasionally to prevent it from sticking or burning. Once warm, whisk in the cocoa powder until fully dissolved and smooth. Add sugar to taste, continue heating until just below boiling, then pour into a mug and serve hot."),
        Recipe("Plain Pasta", listOf("pasta"), "200g pasta; water for boiling; pinch of salt", "Bring a large pot of water to a rolling boil with a generous pinch of salt added. Add the pasta and cook according to the package instructions, usually 8 to 11 minutes, stirring occasionally to prevent sticking. Drain well in a colander and serve immediately, or toss with a sauce of your choice.")
    )
}